// Add the missing using directive:
using System.Collections.Generic;
using Newtonsoft.Json;

// Or install the NuGet package:
// dotnet add package PackageName

// Common fix: add LINQ for collection methods
using System.Linq;

var first = list.FirstOrDefault();

// Explicit cast:
int number = (int)doubleValue;

// Safe conversion:
int number = Convert.ToInt32(stringValue);

// Nullable:
int? nullable = GetValue();
int value = nullable ?? 0;

// BEFORE (wrong)
var result = myObject.GetValue;

// AFTER (correct)
var result = myObject.GetValue();

// BEFORE (warning)
string name = GetName();  // may return null

// AFTER (option 1: nullable type)
string? name = GetName();

// AFTER (option 2: null check)
string name = GetName() ?? "default";

// BEFORE (warning)
var length = name.Length;

// AFTER (null-conditional)
var length = name?.Length ?? 0;

// AFTER (null check)
if (name is not null)
    var length = name.Length;

// Use null-conditional and null-coalescing:
var name = user?.Profile?.Name ?? "Unknown";

// Enable nullable reference types in .csproj:
// <Nullable>enable</Nullable>

// BEFORE (throws on empty)
var item = list.First(x => x.Id == id);

// AFTER (safe)
var item = list.FirstOrDefault(x => x.Id == id);
if (item is null)
    throw new NotFoundException($"Item {id} not found");

// .NET 6+ guard clause:
public void Process(string input)
{
    ArgumentNullException.ThrowIfNull(input);
    // proceed safely
}

try
{
    await context.SaveChangesAsync();
}
catch (DbUpdateException ex)
{
    var innerMessage = ex.InnerException?.Message;
    logger.LogError("DB save failed: {Error}", innerMessage);
    throw;
}

// In Program.cs:
builder.Services.AddScoped<IMyService, MyService>();
builder.Services.AddScoped<MyRepository>();

// Or use AddTransient/AddSingleton as appropriate

[ApiController]
[Route("api/[controller]")]
public class UsersController : ControllerBase
{
    [HttpGet("{id}")]
    public IActionResult GetUser(int id) { ... }
}

// BEFORE (dangerous)
async void ProcessData() {
    await DoWork();  // exception crashes process
}

// AFTER (correct)
async Task ProcessData() {
    await DoWork();  // exception can be caught
}
